parameters.jsCode:
const text = $input.first().json.output;
const chunkSize = 4000;
const chunks = [];

for (let i = 0; i < text.length; i += chunkSize) {
  chunks.push({
    json: {
      chunk: text.slice(i, i + chunkSize),
      index: Math.floor(i / chunkSize) + 1,
      total: Math.ceil(text.length / chunkSize)
    }
  });
}

return chunks;
